import{_ as o,o as t,c as n,a2 as r}from"./chunks/framework.VxKNwi4m.js";const u=JSON.parse('{"title":"관리자 페이지 (Django Admin)","description":"","frontmatter":{},"headers":[],"relativePath":"authority/admin-page.md","filePath":"authority/admin-page.md","lastUpdated":1783168511000}'),e={name:"authority/admin-page.md"};function i(s,a,l,d,g,h){return t(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="관리자-페이지-django-admin" tabindex="-1">관리자 페이지 (Django Admin) <a class="header-anchor" href="#관리자-페이지-django-admin" aria-label="Permalink to &quot;관리자 페이지 (Django Admin)&quot;">​</a></h1><p>시스템의 로우 레벨 데이터 관리, 마스터 데이터 복구 및 프론트엔드에서 지원하지 않는 세부 설정을 수행하는 기술 관리자용 백오피스 도구입니다.</p><ul><li><strong>위치</strong>: <a href="https://ibs.dyibs.com/admin/" target="_blank" rel="noreferrer">ibs.dyibs.com/admin/</a> (스태프 권한 및 로그인 필요)</li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>프론트엔드(Vue)가 정형화된 비즈니스 로직에 따른 업무 처리를 담당한다면, <strong>관리자 페이지</strong>(Django Admin)은 데이터베이스의 모델(Model)에 직접 접근하여 시스템의 근간이 되는 데이터를 제어합니다. 데이터 정합성 오류 수정, 대량 데이터 관리, 프론트엔드 권한 체계의 상위 제어 등을 수행하는 &#39;시스템 마스터 컨트롤러&#39;의 역할을 합니다.</p><h2 id="주요-관리-기능" tabindex="-1">주요 관리 기능 <a class="header-anchor" href="#주요-관리-기능" aria-label="Permalink to &quot;주요 관리 기능&quot;">​</a></h2><ul><li><strong>데이터 전수 관리</strong>: 데이터베이스에 정의된 모든 앱(App)과 테이블(Model)에 대한 CRUD 작업 지원</li><li><strong>사용자 및 그룹 권한 제어</strong>: <strong>최상위 사용자 권한</strong>(<code>is_superuser</code>), <strong>스태프 권한</strong>(<code>is_staff</code>) 등 시스템 레벨의 권한 및 Django 기본 권한 할당</li><li><strong>마스터 데이터 복구</strong>: 잘못 입력된 비즈니스 데이터나 프론트엔드에서 삭제가 제한된 데이터의 강제 수정/삭제</li><li><strong>로그 및 이력 확인</strong>: <strong>관리자 페이지</strong>를 통한 모든 데이터 변경 이력(Log Entry) 추적</li><li><strong>대량 데이터 처리</strong>: <strong>관리자 페이지</strong>(Django Admin)의 Action 기능을 활용한 다수 레코드의 상태 변경 또는 처리</li></ul><h2 id="앱-그룹별-관리-범위" tabindex="-1">앱 그룹별 관리 범위 <a class="header-anchor" href="#앱-그룹별-관리-범위" aria-label="Permalink to &quot;앱 그룹별 관리 범위&quot;">​</a></h2><p>관리자 페이지(Django Admin)은 수많은 앱을 기능별로 그룹화하여 관리합니다.</p><h3 id="_1-계정-및-권한-accounts-auth" tabindex="-1">1. 계정 및 권한 (Accounts &amp; Auth) <a class="header-anchor" href="#_1-계정-및-권한-accounts-auth" aria-label="Permalink to &quot;1. 계정 및 권한 (Accounts &amp; Auth)&quot;">​</a></h3><ul><li><strong>사용자(Users)</strong>: 계정 생성, 비밀번호 강제 재설정, 슈퍼유저 권한 부여, 스태프 상태 관리</li><li><strong>그룹(Groups)</strong>: 특정 직무별 권한 그룹 정의 (현 시스템은 커스텀 권한 체계를 주로 사용함)</li></ul><h3 id="_2-회사-및-프로젝트-company-project" tabindex="-1">2. 회사 및 프로젝트 (Company &amp; Project) <a class="header-anchor" href="#_2-회사-및-프로젝트-company-project" aria-label="Permalink to &quot;2. 회사 및 프로젝트 (Company &amp; Project)&quot;">​</a></h3><ul><li><strong>회사(Company)</strong>: 시스템 운영 주체인 회사 정보의 로우 레벨 관리</li><li><strong>프로젝트(Project)</strong>: 프로젝트 생성, 상태 변경, 귀속 정보 설정</li></ul><h3 id="_3-핵심-비즈니스-데이터-business-core" tabindex="-1">3. 핵심 비즈니스 데이터 (Business Core) <a class="header-anchor" href="#_3-핵심-비즈니스-데이터-business-core" aria-label="Permalink to &quot;3. 핵심 비즈니스 데이터 (Business Core)&quot;">​</a></h3><ul><li><strong>계약/분양</strong>(Contract/Book): 계약 상태, 동호수 지정, 일련번호 등 핵심 계약 정보 관리</li><li><strong>자금/수납</strong>(Ledger/Payment): 입출금 전표, 수납 내역, 정산 일자 등 회계 데이터의 근간 관리</li><li><strong>항목 관리</strong>(Items): 평형 정보, 가격표, 옵션 정보 등 기초 마스터 데이터</li></ul><h3 id="_4-콘텐츠-및-유틸리티-content-utils" tabindex="-1">4. 콘텐츠 및 유틸리티 (Content &amp; Utils) <a class="header-anchor" href="#_4-콘텐츠-및-유틸리티-content-utils" aria-label="Permalink to &quot;4. 콘텐츠 및 유틸리티 (Content &amp; Utils)&quot;">​</a></h3><ul><li><strong>문서/소송</strong>(Docs): 문서 카테고리, 사건 정보, 첨부 파일 데이터 관리</li><li><strong>공지/게시판</strong>(Notice/Board): 게시물 관리, 팝업 설정 등</li><li><strong>엑셀/PDF</strong>(_excel/_pdf): 각종 서식 출력 및 업로드 처리를 위한 설정 데이터</li></ul><h2 id="💡-주요-관리-포인트" tabindex="-1">💡 주요 관리 포인트 <a class="header-anchor" href="#💡-주요-관리-포인트" aria-label="Permalink to &quot;💡 주요 관리 포인트&quot;">​</a></h2><h3 id="직접-수정의-위험성-caution" tabindex="-1">직접 수정의 위험성 (Caution) <a class="header-anchor" href="#직접-수정의-위험성-caution" aria-label="Permalink to &quot;직접 수정의 위험성 (Caution)&quot;">​</a></h3><p><strong>관리자 페이지</strong>(Django Admin)에서의 수정은 프론트엔드의 복잡한 비즈니스 로직(Validation, Signal 등)을 일부 우회할 수 있습니다. 특히 <strong>수납</strong>(Payment)이나 <strong>회계</strong>( Ledger) 데이터를 직접 수정할 경우 정산 데이터의 불일치를 초래할 수 있으므로, 반드시 데이터 구조를 숙지한 관리자만 수행해야 합니다.</p><h3 id="권한의-이중-구조" tabindex="-1">권한의 이중 구조 <a class="header-anchor" href="#권한의-이중-구조" aria-label="Permalink to &quot;권한의 이중 구조&quot;">​</a></h3><p>본 시스템은 Django 기본 권한 외에 <strong>사용자 정의 권한</strong>(<code>StaffAuth</code>)을 별도로 운영합니다. 일반적인 메뉴 노출은 프론트엔드의 <code>권한 설정 관리</code>에서 제어하지만, 관리자 페이지 자체에 접근하려면 Django User 설정의 <strong>스태프 권한</strong>(<code>is_staff</code>) 속성이 반드시 활성화되어 있어야 합니다.</p><h3 id="데이터-정합성-유지" tabindex="-1">데이터 정합성 유지 <a class="header-anchor" href="#데이터-정합성-유지" aria-label="Permalink to &quot;데이터 정합성 유지&quot;">​</a></h3><p>프론트엔드에서 삭제되지 않는 데이터(예: 계약자가 존재하는 동호수 등)를 Admin에서 강제로 삭제할 경우 연관된 데이터들이 고아(Orphan) 상태가 될 수 있습니다. 삭제 전 반드시 연관 관계( ForeignKey)를 확인하십시오.</p><h3 id="백업-대용량-처리" tabindex="-1">백업 대용량 처리 <a class="header-anchor" href="#백업-대용량-처리" aria-label="Permalink to &quot;백업 대용량 처리&quot;">​</a></h3><p>엑셀 업로드 실패 시나 대량의 기초 데이터(동호수 정보 등)를 초기에 밀어넣어야 할 경우, <strong>관리자 페이지</strong>(Django Admin)의 기능을 활용하면 프론트엔드보다 훨씬 빠르게 작업을 수행할 수 있습니다.</p>',26)])])}const m=o(e,[["render",i]]);export{u as __pageData,m as default};
